      //The question mark is used as a separator
      p[0] = '?';
      //Copy the new query string
      osStrncpy(p + 1, queryString, n - 1);
   }

   //Adjust the length of the request header
   context->bufferLen = context->bufferLen + n - m;

   //Successful processing
   return NO_ERROR;
}

